using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // FormatPhoneNumber tests

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParens()
    {
        string result = _formatter.FormatPhoneNumber("5551234567");

        StringAssert.StartsWith(result, "(555)");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        string result = _formatter.FormatPhoneNumber("5551234567");

        StringAssert.EndsWith(result, "4567");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFullFormat()
    {
        string result = _formatter.FormatPhoneNumber("5551234567");

        Assert.AreEqual("(555) 123-4567", result);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
    {
        _formatter.FormatPhoneNumber(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void FormatPhoneNumber_WrongLength_ThrowsArgumentException()
    {
        _formatter.FormatPhoneNumber("123");
    }

    // BuildGreeting tests

    [TestMethod]
    public void BuildGreeting_WithName_StartsWithDear()
    {
        string result = _formatter.BuildGreeting("Smith");

        StringAssert.StartsWith(result, "Dear");
    }

    [TestMethod]
    public void BuildGreeting_WithName_EndsWithComma()
    {
        string result = _formatter.BuildGreeting("Smith");

        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_WithDefaultTitle_ContainsMr()
    {
        string result = _formatter.BuildGreeting("Smith");

        StringAssert.Contains(result, "Mr.");
    }

    [TestMethod]
    public void BuildGreeting_WithCustomTitle_ContainsTitle()
    {
        string result = _formatter.BuildGreeting("Johnson", "Dr.");

        StringAssert.StartsWith(result, "Dear Dr.");
        StringAssert.EndsWith(result, "Johnson,");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void BuildGreeting_WhitespaceName_ThrowsArgumentException()
    {
        _formatter.BuildGreeting("   ");
    }

    // GenerateSlug tests

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseSlug()
    {
        string result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_StartsWithLetters()
    {
        string result = _formatter.GenerateSlug("  ##My Great Post!!  ");

        StringAssert.StartsWith(result, "my");
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_EndsWithLetters()
    {
        string result = _formatter.GenerateSlug("  ##My Great Post!!  ");

        StringAssert.EndsWith(result, "post");
    }

    [TestMethod]
    public void GenerateSlug_MultipleSpaces_CollapseToSingleHyphen()
    {
        string result = _formatter.GenerateSlug("Hello   World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void GenerateSlug_WhitespaceInput_ThrowsArgumentException()
    {
        _formatter.GenerateSlug("   ");
    }

    // FormatCurrency tests

    [TestMethod]
    public void FormatCurrency_WithDefaultSymbol_StartsWithDollarSign()
    {
        string result = _formatter.FormatCurrency(19.99m);

        StringAssert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_WithCustomSymbol_StartsWithSymbol()
    {
        string result = _formatter.FormatCurrency(19.99m, "€");

        StringAssert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimalPlaces()
    {
        string result = _formatter.FormatCurrency(100m);

        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ReturnsFormattedNegative()
    {
        string result = _formatter.FormatCurrency(-5.50m);

        Assert.AreEqual("$-5.50", result);
    }
}

